import { Avatar, EmptyState, MetricCard, PageHeading, ProgressBar, SectionCard, StatusBadge } from "@/components/shared";
import { requireUser } from "@/lib/auth";
import { getDashboardData, getStudentDetail } from "@/lib/data";
import { formatTanggal, rataNilai } from "@/lib/utils";
import { BookOpen, CircleAlert, GraduationCap, Map, Phone, Sparkles, Target } from "lucide-react";
import Link from "next/link";
import { notFound } from "next/navigation";

export default async function StudentDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const user = await requireUser();
  const { id } = await params;
  const visible = await getDashboardData(user);
  if (!visible.students.some((student) => student.id === id)) notFound();
  const detail = await getStudentDetail(id);
  if (!detail) notFound();
  const { student, progress, submissions, weak, targets } = detail;
  const juz = Array.from({ length: 30 }, (_, index) => Math.max(0, Math.min(100, Math.round(progress.percentage * 30 - index * 100))));
  return <><Link href="/progress" className="mb-4 inline-flex items-center gap-1 text-xs font-bold text-emerald-700 hover:text-emerald-900">← Kembali ke progress</Link><PageHeading eyebrow={`Profil Santri · ${student.nis}`} title={student.name} description={`${student.className ?? "Kelas belum diatur"} · ${student.dormName ?? "Asrama belum diatur"} · ${student.halaqahName ?? "Halaqah belum diatur"}`} action={<div className="flex items-center gap-2 rounded-xl border border-slate-200 bg-white px-3 py-2 text-xs font-bold text-slate-600"><Avatar name={student.name} className="size-7"/>{student.gender === "putra" ? "Santri Putra" : "Santri Putri"}</div>}/><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4"><MetricCard label="Capaian hafalan" value={`${progress.percentage}%`} note={`${progress.verses} ayat berstatus lulus`} icon={Map}/><MetricCard label="Nilai rata-rata" value={detail.averageScore || "—"} note="kelancaran, tajwid, makhraj" icon={Sparkles} tone="gold"/><MetricCard label="Surah tercatat" value={progress.surahCount} note="setoran hafalan lulus" icon={BookOpen} tone="sky"/><MetricCard label="Perlu penguatan" value={weak.length} note="setoran belum lulus" icon={CircleAlert} tone={weak.length ? "rose" : "emerald"}/></div><div className="mt-5 grid gap-5 xl:grid-cols-[.9fr_1.1fr]"><SectionCard title="Identitas & target" subtitle="Informasi pembinaan santri"><div className="p-5"><dl className="grid grid-cols-2 gap-x-5 gap-y-4 text-sm"><div><dt className="text-xs text-slate-400">Halaqah</dt><dd className="mt-1 font-bold text-slate-700">{student.halaqahName ?? "—"}</dd></div><div><dt className="text-xs text-slate-400">Musyrif</dt><dd className="mt-1 font-bold text-slate-700">{student.teacherName ?? "—"}</dd></div><div><dt className="text-xs text-slate-400">Wali santri</dt><dd className="mt-1 font-bold text-slate-700">{student.parentName ?? "—"}</dd></div><div><dt className="text-xs text-slate-400">Kontak wali</dt><dd className="mt-1 flex items-center gap-1 font-bold text-slate-700"><Phone size={13}/>{student.parentPhone ?? "—"}</dd></div></dl><div className="mt-6 border-t border-slate-100 pt-4"><p className="mb-3 inline-flex items-center gap-1 text-xs font-bold text-slate-700"><Target size={14} className="text-emerald-600"/>Target aktif</p>{targets.length ? <div className="space-y-3">{targets.map((target) => <div key={target.id} className="rounded-xl bg-emerald-50 p-3"><p className="text-sm font-bold text-emerald-950">{target.programName}</p><p className="mt-1 text-xs text-emerald-800">Harian {target.dailyTarget} · Mingguan {target.weeklyTarget} · Bulanan {target.monthlyTarget}</p></div>)}</div> : <p className="text-sm text-slate-500">Belum ada target khusus. Admin dapat menambahkannya dari Pengaturan.</p>}</div></div></SectionCard><SectionCard title="Peta hafalan" subtitle="Capaian visual berdasarkan ayat berstatus lulus"><div className="p-5"><div className="mb-4"><ProgressBar value={progress.percentage}/></div><div className="grid grid-cols-6 gap-2 sm:grid-cols-10">{juz.map((value, index) => <div key={index} className={`rounded-lg p-1.5 text-center ${value >= 100 ? "bg-emerald-600 text-white" : value > 0 ? "bg-amber-100 text-amber-800" : "bg-slate-100 text-slate-400"}`}><p className="text-[9px] font-bold">{index + 1}</p><p className="text-[8px]">{value}%</p></div>)}</div><div className="mt-4 rounded-xl border border-emerald-100 bg-emerald-50 p-3 text-xs leading-5 text-emerald-800">Progress dihitung secara otomatis dari rentang ayat pada setoran yang berstatus <b>Lulus</b>. Input setoran berikutnya akan memperbarui peta ini.</div></div></SectionCard></div><div className="mt-5 grid gap-5 xl:grid-cols-[1.2fr_.8fr]"><SectionCard title="Riwayat setoran Al-Qur'an" subtitle="Catatan lengkap penilaian ustadz"><div className="divide-y divide-slate-100">{submissions.length ? submissions.map((item) => <article key={item.id} className="px-5 py-4"><div className="flex flex-wrap items-start justify-between gap-3"><div><div className="flex flex-wrap items-center gap-2"><h3 className="font-display text-base font-bold text-slate-800">{item.surah} · ayat {item.verseStart}–{item.verseEnd}</h3><StatusBadge value={item.status}/></div><p className="mt-1 text-xs text-slate-500">{formatTanggal(item.submissionDate)} · {item.teacherName ?? "Ustadz belum tercatat"}</p></div><div className="rounded-lg bg-emerald-50 px-2.5 py-1.5 text-center"><p className="text-sm font-bold text-emerald-700">{rataNilai(item.fluencyScore, item.tajwidScore, item.makhrajScore)}</p><p className="text-[9px] font-bold text-emerald-600">NILAI</p></div></div>{item.notes && <p className="mt-3 rounded-lg bg-slate-50 px-3 py-2 text-xs leading-5 text-slate-600">“{item.notes}”</p>}{item.characterNote && <p className="mt-2 text-[11px] text-emerald-700">Catatan akhlak: {item.characterNote}</p>}</article>) : <EmptyState title="Belum ada riwayat" description="Riwayat muncul setelah ustadz memasukkan setoran."/>}</div></SectionCard><SectionCard title="Hafalan perlu dikuatkan" subtitle="Prioritas muraja'ah dan perbaikan"><div className="divide-y divide-slate-100">{weak.length ? weak.map((item) => <div className="px-5 py-4" key={item.id}><div className="flex items-center justify-between gap-2"><p className="text-sm font-bold text-slate-800">{item.surah} · ayat {item.verseStart}–{item.verseEnd}</p><StatusBadge value={item.status}/></div><p className="mt-2 text-xs leading-5 text-slate-500">{item.notes ?? "Perlu ditinjau kembali bersama musyrif."}</p><p className="mt-2 text-[11px] font-bold text-amber-700">Nilai {rataNilai(item.fluencyScore, item.tajwidScore, item.makhrajScore)} · {formatTanggal(item.submissionDate)}</p></div>) : <EmptyState title="Hafalan aman" description="Belum ada setoran dengan status perlu dikuatkan."/>}</div></SectionCard></div></>;
}
